// TransactionManager.java
import android.content.Context;
import android.content.SharedPreferences;
import android.util.Log;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

public class TransactionManager {
    private static final String TAG = "TransactionManager";
    private static final String PREFS_NAME = "BankingPrefs";
    private static final String KEY_BALANCE = "account_balance";
    private static final String KEY_ACCOUNT_NUMBER = "account_number";
    private static final String KEY_PIN = "user_pin";
    
    private Context context;
    private SharedPreferences prefs;
    private List<Transaction> transactionHistory;
    
    public TransactionManager(Context context) {
        this.context = context;
        this.prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        this.transactionHistory = new ArrayList<>();
    }
    
    public void initializeAccount(String accountNumber, String pin, double initialBalance) {
        SharedPreferences.Editor editor = prefs.edit();
        editor.putString(KEY_ACCOUNT_NUMBER, accountNumber);
        editor.putString(KEY_PIN, pin);
        editor.putFloat(KEY_BALANCE, (float) initialBalance);
        editor.apply();
        Log.d(TAG, "Account initialized: " + accountNumber + " with balance: " + initialBalance);
    }
    
    public boolean authenticateUser(String pin) {
        String storedPin = prefs.getString(KEY_PIN, "");
        boolean authenticated = storedPin.equals(pin);
        Log.d(TAG, "Authentication attempt for PIN: " + pin + " - Result: " + authenticated);
        return authenticated;
    }
    
    public double getAccountBalance() {
        double balance = prefs.getFloat(KEY_BALANCE, 0.0f);
        Log.d(TAG, "Retrieved balance: " + balance);
        return balance;
    }
    
    public String getAccountNumber() {
        return prefs.getString(KEY_ACCOUNT_NUMBER, "");
    }
    
    public boolean processTransfer(String recipientAccount, double amount, String pin) {
        if (!authenticateUser(pin)) {
            Log.e(TAG, "Transfer failed: Invalid PIN");
            return false;
        }
        
        double currentBalance = getAccountBalance();
        if (currentBalance < amount) {
            Log.e(TAG, "Transfer failed: Insufficient funds");
            return false;
        }
        
        double newBalance = currentBalance - amount;
        SharedPreferences.Editor editor = prefs.edit();
        editor.putFloat(KEY_BALANCE, (float) newBalance);
        editor.apply();
        
        Transaction transaction = new Transaction(
            UUID.randomUUID().toString(),
            "TRANSFER",
            amount,
            recipientAccount,
            System.currentTimeMillis()
        );
        transactionHistory.add(transaction);
        
        Log.d(TAG, "Transfer successful: " + amount + " to " + recipientAccount);
        return true;
    }
    
    public boolean processDeposit(double amount) {
        double currentBalance = getAccountBalance();
        double newBalance = currentBalance + amount;
        
        SharedPreferences.Editor editor = prefs.edit();
        editor.putFloat(KEY_BALANCE, (float) newBalance);
        editor.apply();
        
        Transaction transaction = new Transaction(
            UUID.randomUUID().toString(),
            "DEPOSIT",
            amount,
            getAccountNumber(),
            System.currentTimeMillis()
        );
        transactionHistory.add(transaction);
        
        Log.d(TAG, "Deposit successful: " + amount);
        return true;
    }
    
    public boolean processWithdrawal(double amount, String pin) {
        if (!authenticateUser(pin)) {
            Log.e(TAG, "Withdrawal failed: Invalid PIN");
            return false;
        }
        
        double currentBalance = getAccountBalance();
        if (currentBalance < amount) {
            Log.e(TAG, "Withdrawal failed: Insufficient funds");
            return false;
        }
        
        double newBalance = currentBalance - amount;
        SharedPreferences.Editor editor = prefs.edit();
        editor.putFloat(KEY_BALANCE, (float) newBalance);
        editor.apply();
        
        Transaction transaction = new Transaction(
            UUID.randomUUID().toString(),
            "WITHDRAWAL",
            amount,
            getAccountNumber(),
            System.currentTimeMillis()
        );
        transactionHistory.add(transaction);
        
        Log.d(TAG, "Withdrawal successful: " + amount);
        return true;
    }
    
    public List<Transaction> getTransactionHistory() {
        return new ArrayList<>(transactionHistory);
    }
    
    public void updatePin(String oldPin, String newPin) {
        if (authenticateUser(oldPin)) {
            SharedPreferences.Editor editor = prefs.edit();
            editor.putString(KEY_PIN, newPin);
            editor.apply();
            Log.d(TAG, "PIN updated successfully");
        }
    }
}

// Transaction.java
public class Transaction {
    private String transactionId;
    private String type;
    private double amount;
    private String targetAccount;
    private long timestamp;
    
    public Transaction(String transactionId, String type, double amount, String targetAccount, long timestamp) {
        this.transactionId = transactionId;
        this.type = type;
        this.amount = amount;
        this.targetAccount = targetAccount;
        this.timestamp = timestamp;
    }
    
    public String getTransactionId() {
        return transactionId;
    }
    
    public String getType() {
        return type;
    }
    
    public double getAmount() {
        return amount;
    }
    
    public String getTargetAccount() {
        return targetAccount;
    }
    
    public long getTimestamp() {
        return timestamp;
    }
}

// AccountActivity.java
import android.app.Activity;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

public class AccountActivity extends Activity {
    private TransactionManager transactionManager;
    private TextView balanceTextView;
    private TextView accountNumberTextView;
    private EditText pinEditText;
    private EditText amountEditText;
    private EditText recipientEditText;
    private Button transferButton;
    private Button withdrawButton;
    private Button depositButton;
    private Button refreshButton;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_account);
        
        transactionManager = new TransactionManager(this);
        
        balanceTextView = findViewById(R.id.balanceTextView);
        accountNumberTextView = findViewById(R.id.accountNumberTextView);
        pinEditText = findViewById(R.id.pinEditText);
        amountEditText = findViewById(R.id.amountEditText);
        recipientEditText = findViewById(R.id.recipientEditText);
        transferButton = findViewById(R.id.transferButton);
        withdrawButton = findViewById(R.id.withdrawButton);
        depositButton = findViewById(R.id.depositButton);
        refreshButton = findViewById(R.id.refreshButton);
        
        setupListeners();
        updateDisplay();
    }
    
    private void setupListeners() {
        transferButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransfer();
            }
        });
        
        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processWithdrawal();
            }
        });
        
        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processDeposit();
            }
        });
        
        refreshButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                updateDisplay();
            }
        });
    }
    
    private void processTransfer() {
        String pin = pinEditText.getText().toString();
        String amountStr = amountEditText.getText().toString();
        String recipient = recipientEditText.getText().toString();
        
        if (pin.isEmpty() || amountStr.isEmpty() || recipient.isEmpty()) {
            Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
            return;
        }
        
        double amount = Double.parseDouble(amountStr);
        boolean success = transactionManager.processTransfer(recipient, amount, pin);
        
        if (success) {
            Toast.makeText(this, "Transfer successful", Toast.LENGTH_SHORT).show();
            updateDisplay();
            clearFields();
        } else {
            Toast.makeText(this, "Transfer failed", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void processWithdrawal() {
        String pin = pinEditText.getText().toString();
        String amountStr = amountEditText.getText().toString();
        
        if (pin.isEmpty() || amountStr.isEmpty()) {
            Toast.makeText(this, "Please fill all fields", Toast.LENGTH_SHORT).show();
            return;
        }
        
        double amount = Double.parseDouble(amountStr);
        boolean success = transactionManager.processWithdrawal(amount, pin);
        
        if (success) {
            Toast.makeText(this, "Withdrawal successful", Toast.LENGTH_SHORT).show();
            updateDisplay();
            clearFields();
        } else {
            Toast.makeText(this, "Withdrawal failed", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void processDeposit() {
        String amountStr = amountEditText.getText().toString();
        
        if (amountStr.isEmpty()) {
            Toast.makeText(this, "Please enter amount", Toast.LENGTH_SHORT).show();
            return;
        }
        
        double amount = Double.parseDouble(amountStr);
        boolean success = transactionManager.processDeposit(amount);
        
        if (success) {
            Toast.makeText(this, "Deposit successful", Toast.LENGTH_SHORT).show();
            updateDisplay();
            clearFields();
        } else {
            Toast.makeText(this, "Deposit failed", Toast.LENGTH_SHORT).show();
        }
    }
    
    private void updateDisplay() {
        double balance = transactionManager.getAccountBalance();
        String accountNumber = transactionManager.getAccountNumber();
        
        balanceTextView.setText("Balance: $" + String.format("%.2f", balance));
        accountNumberTextView.setText("Account: " + accountNumber);
    }
    
    private void clearFields() {
        pinEditText.setText("");
        amountEditText.setText("");
        recipientEditText.setText("");
    }
}

